import type { ApplicationId } from "./applications/brett-application";
import { getApplicationDomain } from "./env";
import { InstalledApplication } from "./installations";
import type { OrganizationId } from "./organizations";

/**
 * @public
 */
export class MediaLibraryApplication extends InstalledApplication<"media-library"> {
  constructor(id: ApplicationId, organizationId: OrganizationId) {
    super({ type: "media-library", slug: "media-library", id, organizationId });
  }

  get href(): string {
    return "media";
  }

  get title(): string {
    return "Media Library";
  }

  get url(): URL {
    return new URL(
      `https://${this.slug}-apps-${this.organizationId}.${getApplicationDomain()}`,
    );
  }
}
